266	pub fn error(span: Span, message: &str, place: &str) {
267	    if !RUNNING_TESTS.lock().unwrap().clone() {
268	        report(span.line, span.column, message, place);
269	
270	        panic::set_hook(Box::new(|_| {}));
271	    }
272	}
