288	pub fn report(line: usize, column: usize, message: &str, place: &str) {
289	    let mut err = ERROR.lock().unwrap();
290	
291	    println!(
292	        "\n{BOLD}{ERROR_COLOR}error{RESET} {HELP_COLOR}({place}){RESET}{BOLD}: {message}{RESET}"
293	    );
294	
295	    println!("--> line {} column {}\n", line, column);
296	
297	    let source_line = get_line(line);
298	
299	    println!("    |");
300	    if line as isize - 3 > 0 {
301	        let prev_line = get_line(line - 3);
302	        println!("{CYAN}{:>3}{RESET} | {}", line - 3, prev_line);
303	    }
304	
305	    if line as isize - 2 > 0 {
306	        let prev_line = get_line(line - 2);
307	        println!("{CYAN}{:>3}{RESET} | {}", line - 2, prev_line);
308	    }
309	
310	    if line as isize - 1 > 0 {
311	        let prev_line = get_line(line - 1);
312	        println!("{CYAN}{:>3}{RESET} | {}", line - 1, prev_line);
313	    }
314	    println!("{CYAN}{:>3}{RESET} | {}", line, source_line);
315	
316	    let prefix_len = format!("{:>3}  | ", line).len();
317	    let caret_padding = " ".repeat((prefix_len + column).saturating_sub(3));
318	
319	    let mut caret_line = format!("{}{ERROR_COLOR}^{RESET} {message}", caret_padding);
320	
321	    caret_line.replace_range(4..4, "|");
322	
323	    println!("{}", caret_line);
324	
325	    let stack = CALL_STACK.lock().unwrap();
326	    if !stack.is_empty() {
327	        println!("\n{BOLD}Stack trace:{RESET}");
328	        for func in stack.iter().rev() {
329	            println!("  {BRIGHT_YELLOW}->{BRIGHT_BLUE} {}", func);
330	        }
331	    }
332	
333	    println!("{RESET}\n");
334	
335	    *err = Err(ObstructError::new(line, column, message));
336	}
