24	impl CompileTimeEnv {
25	    pub fn new(ctx: &mut CodeGenContext) -> CompileTimeEnv {
26	        let mut this = CompileTimeEnv {
27	            all_types: Vec::new(),
28	            scopes: vec![HashMap::new()],
29	            current_scope: 0,
30	
31	            these: Vec::new(),
32	
33	            members: HashMap::new(),
34	
35	            next_var_id: 0,
36	            next_type_id: 0,
37	
38	            generic_functions: Vec::new(),
