40	
41	        this.register_type(Type::simple("i32"));
42	        this.register_type(Type::simple("arr"));
43	        this.register_type(Type::simple("f64"));
44	        this.register_type(Type::simple("bool"));
45	        this.register_type(Type::simple("char"));
46	        this.register_type(Type::simple("func"));
47	        this.register_type(Type::simple("strlit"));
48	
49	        // Declare and register _print: func(i32) -> arr
50	        this.declare_global_var(
51	            "_print".to_string(),
52	            false,
53	            Type::with_generics("func", vec![Type::simple("i32"), nil_type()]),
54	        );
55	        this.add_func_type(nil_type(), vec![Type::simple("i32")], ctx, Span::empty());
56	
57	        // Declare and register _add: func(i32, i32) -> i32
58	        this.declare_global_var(
59	            "_add".to_string(),
60	            false,
61	            Type::with_generics(
62	                "func",
63	                vec![
64	                    Type::simple("i32"),
65	                    Type::simple("i32"),
66	                    Type::simple("i32"),
67	                ],
68	            ),
69	        );
70	        this.add_func_type(
71	            Type::simple("i32"),
72	            vec![Type::simple("i32"), Type::simple("i32")],
73	            ctx,
74	            Span::empty(),
75	        );
76	
77	        // Declare and register _less: func(i32, i32) -> i32
78	        this.declare_global_var(
79	            "_less".to_string(),
80	            false,
81	            Type::with_generics(
82	                "func",
83	                vec![
84	                    Type::simple("i32"),
85	                    Type::simple("i32"),
86	                    Type::simple("i32"),
