350	    // Variable Handling
351	
352	    pub fn declare_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
353	        let id = self.next_var_id;
354	        self.next_var_id += 1;
355	
356	        let scope = self.scopes.last_mut().unwrap();
357	        scope.insert(name, (id, is_mutable, var_type));
358	
359	        id
360	    }
361	
362	    pub fn declare_global_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
363	        let id = self.next_var_id;
364	        self.next_var_id += 1;
365	
366	        let scope = self.scopes.first_mut().unwrap();
367	        scope.insert(name, (id, is_mutable, var_type));
368	
369	        id
370	    }
