11	    pub fn to_c(&self, cte: &mut CompileTimeEnv, ctx: &mut CodeGenContext) -> bool {
12	        // if true - requires a semicolon at end of statement
13	        match self {
14	            Expr::Int(n) => {
15	                ctx.body.push_str(&n.to_string());
16	                false
17	            }
18	            Expr::Float(n) => {
19	                if n.fract() == 0.0 {
20	                    ctx.body.push_str(&n.to_string());
21	                    ctx.body.push_str(".0");
22	                } else {
23	                    ctx.body.push_str(&n.to_string());
24	                }
25	                false
26	            }
27	
28	            Expr::Bool(b) => {
29	                ctx.body.push_str(if *b { "true" } else { "false" });
30	                false
31	            }
32	            Expr::Char(c) => {
33	                ctx.body.push('\'');
34	                ctx.body.push_str(&c.to_string());
35	                ctx.body.push('\'');
36	                false
37	            }
38	            Expr::Str(s) => {
39	                ctx.body.push('"');
40	                for c in s.chars() {
41	                    match c {
42	                        '\n' => ctx.body.push_str("\\n"),
43	                        '\t' => ctx.body.push_str("\\t"),
44	                        _ => ctx.body.push(c),
45	                    }
46	                }
47	                ctx.body.push('"');
48	                false
49	            }
