51	            Expr::Add(l, r, span) => {
52	                Expr::CallFunc(
53	                    "_add".into(),
54	                    vec![l.get_type(cte)],
55	                    vec![l.clone(), r.clone()],
56	                    *span,
57	                )
58	                .to_c(cte, ctx);
59	                false
60	            }
