177	            Expr::If(if_cond, if_block, else_block, is_expr) => {
178	                if !is_expr {
179	                    ctx.body.push_str("if (");
180	                    if_cond.to_c(cte, ctx);
181	                    ctx.body.push_str(")");
182	                    if_block.to_c(cte, ctx);
183	                    if else_block.is_some() {
184	                        ctx.body.push_str(" else ");
185	                        else_block.clone().unwrap().to_c(cte, ctx);
186	                    }
187	                } else {
188	                    error(
189	                        if_cond.get_span(),
190	                        "EXPRESSION IF STATEMENTS NOT IMPLEMENTED",
191	                        "transpiling",
192	                    );
193	                }
194	
195	                let else_type = if let Some(ty) = else_block {
196	                    ty.get_type(cte)
197	                } else {
198	                    nil_type()
199	                };
200	                if if_block.get_type(cte) != else_type {
201	                    error(
202	                        if_block.get_span(),
203	                        "if and else blocks had different types",
204	                        "transpiling",
205	                    );
206	                }
207	
208	                false
209	            }
210	
211	            Expr::StmtBlockWithScope(exprs, span) => {
212	                cte.push_scope();
213	                ctx.body.push_str("{\n");
214	                Expr::StmtBlock(exprs.clone(), *span).to_c(cte, ctx);
215	                ctx.body.push('}');
216	                cte.pop_scope();
217	                false
218	            }
219	
220	            Expr::Print(expr, span) => {
221	                Expr::CallFunc(
222	                    "_print".into(),
223	                    vec![expr.get_type(cte)],
224	                    vec![expr.clone()],
225	                    *span,
226	                )
227	                .to_c(cte, ctx);
228	                true
229	            }
230	
231	            Expr::Discard(expr) => {
232	                expr.to_c(cte, ctx);
233	                true
234	            }
235	
236	            Expr::Variable(name, span) => {
237	                ctx.body.push_str(&cte.c_var_name(name, *span));
238	                false
239	            }
240	
241	            Expr::This(span) => {
242	                ctx.body.push(' ');
243	                ctx.body.push_str(&cte.c_var_name(cte.this(), *span));
244	                ctx.body.push(' ');
245	                false
246	            }
247	
248	            Expr::Declare(name, var_type, expr, is_mutable, span) => {
249	                let var_type = if var_type.is_some() {
250	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone().unwrap());
251	                    var_type.clone().unwrap()
252	                } else {
253	                    let t = expr.clone().unwrap().get_type(cte);
254	                    cte.declare_var(name.clone(), *is_mutable, t.clone());
255	                    t
256	                };
257	
258	                ctx.body += format!(
259	                    "{} {}",
260	                    cte.c_type_name(&var_type, *span),
261	                    cte.c_var_name(&name, *span),
262	                )
263	                .as_str();
264	
265	                if expr.is_some() {
266	                    ctx.body.push('=');
267	                    expr.clone().unwrap().to_c(cte, ctx);
268	                }
269	                true
270	            }
271	
272	            Expr::CallFunc(name, gens, exprs, span) => {
273	                if !cte.var_exists(name) {
274	                    error(
275	                        *span,
276	                        &format!("Function '{}' does not exist", name),
277	                        "transpiling",
278	                    );
279	                }
280	                ctx.body
281	                    .push_str(format!("{}(", cte.c_func_instance_name(name, gens, *span)).as_str());
282	                for expr in exprs {
283	                    expr.to_c(cte, ctx);
284	                    ctx.body.push(',');
285	                }
286	                if exprs.len() >= 1 {
287	                    ctx.body.pop();
288	                }
289	
290	                ctx.body.push_str(")");
291	                true
292	            }
293	
294	            Expr::Stmt(expr) => {
295	                expr.to_c(cte, ctx);
296	                true
297	            }
298	
299	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
300	                let mut arg_types = vec![];
301	                for arg in args {
302	                    arg_types.push(arg.1.clone());
303	                }
304	
305	                // Push scope and declare parameters BEFORE computing returned_type,
306	                // so that parameter variables are visible during type inference.
307	                cte.push_scope();
308	                for arg in args {
309	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
310	                }
311	
312	                let ret_type = block.returned_type(cte, *span);
313	                let return_type = if return_type.is_some() {
314	                    return_type.clone().unwrap()
315	                } else {
316	                    if let Some(ty) = ret_type.clone() {
317	                        ty
318	                    } else {
319	                        nil_type()
320	                    }
321	                };
322	
323	                ctx.body.push_str(
324	                    format!(
325	                        "{} {}(",
326	                        cte.c_type_name(&return_type, *span),
327	                        cte.c_func_instance_name(&name, &[], *span),
328	                    )
329	                    .as_str(),
330	                );
331	
332	                for arg in args {
333	                    ctx.body.push_str(&cte.c_type_name(&arg.1, *span));
334	                    ctx.body.push(' ');
335	                    ctx.body.push_str(&cte.c_var_name(&arg.0, *span));
336	                    ctx.body.push_str(", ");
337	                }
338	                if ctx.body.ends_with(", ") {
339	                    ctx.body.pop();
340	                    ctx.body.pop();
341	                }
342	
343	                ctx.body.push(')');
344	
345	                block.to_c(cte, ctx);
346	
347	                cte.pop_scope();
348	
349	                false
350	            }
351	
352	            Expr::Assign(left, right, span) => {
353	                match left.as_ref() {
354	                    Expr::Variable(name, _) => {
355	                        cte.push_this(name);
356	                        ctx.body.push_str(&cte.c_var_name(name, *span));
357	                        ctx.body.push('=');
358	                        right.to_c(cte, ctx);
359	                        cte.pop_this();
360	                    }
361	                    Expr::Member(var, member, span) => {
362	                        ctx.body.push_str(&cte.c_var_name(var, *span));
363	                        ctx.body.push('.');
364	                        ctx.body.push_str(
365	                            &cte.c_member_name(
366	                                &cte.get_var(var)
367	                                    .unwrap_or_else(|| {
368	                                        error(
369	                                            *span,
370	                                            &format!("Could not find variable '{}'", var),
371	                                            "transpiling",
372	                                        );
373	                                        (false, nil_type())
374	                                    })
375	                                    .1,
376	                                member,
377	                                *span,
378	                            ),
379	                        );
380	                        ctx.body.push('=');
381	                        right.to_c(cte, ctx);
382	                    }
383	                    _ => {
384	                        error(*span, "Invalid assignment target", "transpiler");
385	                    }
386	                }
387	                true
388	            }
389	
390	            Expr::Return(expr, _span) => {
391	                ctx.body.push_str("return ");
392	                expr.to_c(cte, ctx);
393	                true
394	            }
395	
396	            Expr::Delete(name) => {
397	                cte.del_var(name);
398	                false
399	            }
400	
401	            Expr::Nothing() => false,
402	
403	            Expr::While(cond, block) => {
404	                ctx.body.push_str("while (");
405	                cond.to_c(cte, ctx);
406	                ctx.body.push_str("){\n");
407	                block.to_c(cte, ctx);
408	                ctx.body.push_str("}");
409	                false
410	            }
411	
412	            Expr::Input(name) => {
413	                ctx.body.push_str("scanf(\"%d\",&");
414	                ctx.body.push_str(&cte.c_var_name(name, Span::empty()));
415	                ctx.body.push_str(")");
416	                true
417	            }
418	
419	            Expr::Use { .. } => false,
420	
421	            Expr::Class(ty, members, span) => {
422	                let c_type_name = cte.c_type_name(ty, *span);
423	                ctx.types.push_str("struct ");
424	                ctx.types.push_str(&c_type_name);
425	                ctx.types.push_str(" {\n");
426	                for member in members {
427	                    ctx.types.push_str(&cte.c_type_name(&member.1, *span));
428	                    ctx.types.push(' ');
429	                    ctx.types.push_str(&cte.c_member_name(ty, &member.0, *span));
430	                    ctx.types.push_str("; \n");
431	                }
432	                if ctx.types.ends_with("; \n") {
433	                    ctx.types.pop();
434	                    ctx.types.pop();
435	                    ctx.types.push('\n');
436	                }
437	                ctx.types.push_str("};\n");
438	
439	                true
440	            }
441	
442	            Expr::Member(variable, member, span) => {
443	                ctx.body.push_str(&cte.c_var_name(variable, *span));
444	                ctx.body.push('.');
445	
446	                let var = cte.get_var(variable);
447	                if var.is_none() {
448	                    error(
449	                        *span,
450	                        &format!("Variable '{}' not defined", variable),
451	                        "type checker",
452	                    );
453	                }
454	                let variable = var.unwrap();
455	                ctx.body
456	                    .push_str(&cte.c_member_name(&variable.1, member, *span));
457	                false
458	            }
459	
460	            _ => panic!("unexpected expression (for transpilation) '{:?}'", self),
461	        }
462	    }
