464	    pub fn pre_transpile(
465	        &self,
466	        cte: &mut CompileTimeEnv,
467	        ctx: &mut CodeGenContext,
468	        programs_to_transpile: &mut HashMap<String, bool>,
469	    ) {
470	        match self {
471	            Expr::DeclareFunction(name, block, return_type, args, _gens, span) => {
472	                if cte.get_var(name).is_some() {
473	                    error(
474	                    *span,
475	                    format!(
476	                        "Variable '{}' already exists and is immutable, could not declare function",
477	                        name
478	                    )
479	                        .as_str(),"pre-transpiling"
480	                );
481	                }
482	                let mut arg_types = vec![];
483	                for arg in args {
484	                    arg_types.push(arg.1.clone());
485	                }
486	
487	                // Push scope and declare parameters BEFORE computing returned_type,
488	                // so that parameter variables are visible during type inference.
489	                cte.push_scope();
490	                for arg in args {
491	                    cte.declare_var(arg.0.clone(), false, arg.1.clone());
492	                }
493	
494	                let ret_type = block.returned_type(cte, *span);
495	                let return_type = if return_type.is_some() {
496	                    return_type.clone().unwrap()
497	                } else {
498	                    if let Some(ty) = ret_type.clone() {
499	                        ty
500	                    } else {
501	                        nil_type()
502	                    }
503	                };
504	
505	                cte.add_func_type(return_type.clone(), arg_types.clone(), ctx, *span);
506	                // Declare the variable first so c_func_instance_name can find it
507	                cte.declare_global_var(
508	                    name.clone(),
509	                    false,
510	                    Type::with_generics("func", {
511	                        arg_types.push(return_type.clone());
512	                        let output = arg_types;
513	                        output
514	                    }),
515	                );
516	
517	                ctx.declarations.push_str(
518	                    format!(
519	                        "{} {}(",
520	                        cte.c_type_name(&return_type, *span),
521	                        cte.c_func_instance_name(&name, &[], *span),
522	                    )
523	                    .as_str(),
524	                );
525	
526	                for arg in args {
527	                    ctx.declarations.push_str(&cte.c_type_name(&arg.1, *span));
528	                    ctx.declarations.push(' ');
529	                    ctx.declarations.push_str(&cte.c_var_name(&arg.0, *span));
530	                    ctx.declarations.push_str(", ");
531	                }
532	                if ctx.declarations.ends_with(", ") {
533	                    ctx.declarations.pop();
534	                    ctx.declarations.pop();
535	                }
536	
537	                ctx.declarations.push_str(");\n");
538	
539	                block.pre_transpile(cte, ctx, programs_to_transpile);
540	
541	                cte.pop_scope();
542	            }
543	            Expr::Use { kind, path, span } => {
544	                let crate_path = match kind {
545	                    UseKind::Std => STD_PATH,
546	                    UseKind::Normal => "",
547	                };
548	
549	                let full_path = format!("{}{}", crate_path, path);
550	
551	                if !Path::new(&full_path).exists() {
552	                    error(*span, "File does not exist!", "pre-transpiling");
553	                }
554	
555	                if !programs_to_transpile.contains_key(&full_path) {
556	                    programs_to_transpile.insert(full_path, false);
557	                }
558	            }
559	
560	            Expr::StmtBlock(exprs, _) | Expr::StmtBlockWithScope(exprs, _) => {
561	                for expr in exprs {
562	                    expr.pre_transpile(cte, ctx, programs_to_transpile);
563	                }
564	            }
565	
566	            Expr::Discard(expr) => expr.pre_transpile(cte, ctx, programs_to_transpile),
567	
568	            Expr::Class(ty, members, span) => {
569	                cte.register_class(ty.clone());
570	
571	                for member in members {
572	                    cte.declare_member(member.0.clone(), member.1.clone(), ty.clone());
573	                }
574	
575	                let c_type_name = cte.c_type_name(ty, *span);
576	                ctx.include.push_str("struct ");
577	                ctx.include.push_str(&c_type_name);
578	                ctx.include.push_str(";\n");
579	
580	                ctx.types.push_str("\ntypedef struct ");
581	                ctx.types.push_str(&c_type_name);
582	                ctx.types.push(' ');
583	                ctx.types.push_str(&c_type_name);
584	                ctx.types.push_str(";\n");
585	            }
586	
587	            Expr::Declare(name, var_type, expr, is_mutable, _span) => {
588	                if let Some(var_type) = var_type {
589	                    cte.declare_var(name.clone(), *is_mutable, var_type.clone());
590	                } else if let Some(expr_box) = expr {
591	                    let t = expr_box.get_type(cte);
592	                    cte.declare_var(name.clone(), *is_mutable, t);
593	                }
594	                if let Some(expr_box) = expr {
595	                    expr_box.pre_transpile(cte, ctx, programs_to_transpile);
596	                }
597	            }
598	
599	            _ => {}
600	        }
601	    }
