412	    fn call_function(&mut self, name: String) -> Expr {
413	        let mut generics = vec![];
414	
415	        if self.match_any(&[TokenType::LessLess]) {
416	            loop {
417	                generics.push(self.get_type());
418	
419	                if !self.match_any(&[TokenType::Comma]) {
420	                    break;
421	                }
422	            }
423	            self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
424	        }
425	
426	        self.consume(TokenType::LeftParen, "Expected '(' after function name.");
427	
428	        let mut arguments = vec![];
429	
430	        if !self.check(TokenType::RightParen) {
431	            loop {
432	                arguments.push(Box::new(self.expression()));
433	                if !self.match_any(&[TokenType::Comma]) {
434	                    break;
435	                }
436	            }
437	        }
438	
439	        self.consume(TokenType::RightParen, "Missing ')' after function call.");
440	
441	        Expr::CallFunc(name, generics, arguments, self.get_span())
442	    }
