444	    // ---------- EXPRESSIONS ----------
445	    fn expression(&mut self) -> Expr {
446	        self.bools()
447	    }
448	
449	    fn bools(&mut self) -> Expr {
450	        let mut expr = self.compare();
451	
452	        while self.match_any(&[TokenType::And, TokenType::Or]) {
453	            let op = self.previous().token_type;
454	            let right = self.compare();
455	            expr = match op {
456	                TokenType::And => Expr::And(Box::new(expr), Box::new(right), self.get_span()),
457	                TokenType::Or => Expr::Or(Box::new(expr), Box::new(right), self.get_span()),
458	                _ => unreachable!(),
459	            };
460	        }
461	
462	        expr
463	    }
464	
465	    fn compare(&mut self) -> Expr {
466	        let mut expr = self.term();
467	
468	        while self.match_any(&[
469	            TokenType::EqualEqual,
470	            TokenType::BangEqual,
471	            TokenType::Greater,
472	            TokenType::GreaterEqual,
473	            TokenType::Less,
474	            TokenType::LessEqual,
475	        ]) {
476	            let op = self.previous().token_type;
477	            let right = self.term();
478	            expr = match op {
479	                TokenType::EqualEqual => {
480	                    Expr::EqualEqual(Box::new(expr), Box::new(right), self.get_span())
481	                }
482	                TokenType::BangEqual => {
483	                    Expr::BangEqual(Box::new(expr), Box::new(right), self.get_span())
484	                }
485	                TokenType::Greater => {
486	                    Expr::Greater(Box::new(expr), Box::new(right), self.get_span())
487	                }
488	                TokenType::GreaterEqual => {
489	                    Expr::GreaterEqual(Box::new(expr), Box::new(right), self.get_span())
490	                }
491	                TokenType::Less => Expr::Less(Box::new(expr), Box::new(right), self.get_span()),
492	                TokenType::LessEqual => {
493	                    Expr::LessEqual(Box::new(expr), Box::new(right), self.get_span())
494	                }
495	                _ => unreachable!(),
496	            };
497	        }
498	
499	        expr
500	    }
501	
502	    fn term(&mut self) -> Expr {
503	        let mut expr = self.factor();
504	
505	        while self.match_any(&[TokenType::Plus, TokenType::Minus]) {
506	            let op = self.previous().token_type;
507	            let right = self.factor();
508	            expr = match op {
509	                TokenType::Plus => Expr::Add(Box::new(expr), Box::new(right), self.get_span()),
510	                TokenType::Minus => Expr::Sub(Box::new(expr), Box::new(right), self.get_span()),
511	                _ => unreachable!(),
512	            };
513	        }
514	
515	        expr
516	    }
517	
518	    fn factor(&mut self) -> Expr {
519	        let mut expr = self.unary();
520	
521	        while self.match_any(&[TokenType::Star, TokenType::Slash, TokenType::Mod]) {
522	            let op = self.previous().token_type;
523	            let right = self.unary();
524	            expr = match op {
525	                TokenType::Star => Expr::Mult(Box::new(expr), Box::new(right), self.get_span()),
526	                TokenType::Slash => Expr::Div(Box::new(expr), Box::new(right), self.get_span()),
527	                TokenType::Mod => Expr::Mod(Box::new(expr), Box::new(right), self.get_span()),
528	                _ => unreachable!(),
529	            };
530	        }
531	
532	        expr
533	    }
534	
535	    fn unary(&mut self) -> Expr {
536	        if self.match_any(&[TokenType::Minus]) {
537	            return Expr::Sub(
538	                Box::new(Expr::Nothing()),
539	                Box::new(self.unary()),
540	                self.get_span(),
541	            );
542	        }
543	
544	        if self.match_any(&[TokenType::Plus]) {
545	            return Expr::Add(
546	                Box::new(Expr::Nothing()),
547	                Box::new(self.unary()),
548	                self.get_span(),
549	            );
550	        }
551	
552	        if self.match_any(&[TokenType::Bang]) {
553	            return Expr::Not(Box::new(self.unary()));
554	        }
555	
556	        if self.match_any(&[TokenType::And]) {
557	            // Make a reference to the variable itself
558	            return if self.check(TokenType::Ident) {
559	                self.advance(); // consume the identifier
560	                let var_name = self.previous().lexeme.clone();
561	                Expr::CallFunc(
562	                    "ref::new".into(),
563	                    vec![],
564	                    vec![Box::new(Expr::Str(var_name))],
565	                    self.get_span(),
566	                )
567	            } else {
568	                error(self.get_span(), "Expected identifier after '&'.", "parsing");
569	                Expr::Nothing()
570	            };
571	        }
572	
573	        if self.match_any(&[TokenType::Star]) {
574	            let expr = self.unary();
575	            return Expr::CallFunc(
576	                "ref::deref".into(),
577	                vec![],
578	                vec![Box::new(expr)],
579	                self.get_span(),
580	            );
581	        }
582	
583	        self.power()
584	    }
585	
586	    fn power(&mut self) -> Expr {
587	        let mut expr = self.nth();
588	
589	        while self.match_any(&[TokenType::StarStar]) {
590	            expr = Expr::Power(Box::new(expr), Box::new(self.nth()), self.get_span());
591	        }
592	
593	        expr
594	    }
595	    fn nth(&mut self) -> Expr {
596	        let val = self.primary();
597	        if self.match_any(&[TokenType::LeftBrack]) {
598	            let expr = self.expression();
599	            self.consume(TokenType::RightBrack, "Expected ']' after indexing.");
600	            Expr::Nth(Box::new(val), Box::new(expr), self.get_span())
601	        } else {
602	            val
603	        }
604	    }
605	
606	    fn vector_lit(&mut self) -> Expr {
607	        if self.match_any(&[TokenType::LeftBrace]) {
608	            let mut exprs = vec![];
609	
610	            let mut last_expr = false;
611	            while !self.match_any(&[TokenType::RightBrace]) && !last_expr {
612	                let expr = self.expression();
613	                exprs.push(expr);
614	                if !self.match_any(&[TokenType::Comma]) {
615	                    last_expr = true;
616	                }
617	            }
618	
619	            Expr::Vector(exprs)
620	        } else {
621	            self.consume(TokenType::LeftBrace, "Expected '{' after '\\''.");
622	            Expr::Nothing()
623	        }
624	    }
625	
626	    fn array_lit(&mut self) -> Expr {
627	        let mut exprs = vec![];
628	
629	        let mut last_expr = false;
630	        while !self.match_any(&[TokenType::RightBrack]) && !last_expr {
631	            let expr = self.expression();
632	            exprs.push(expr);
633	            if !self.match_any(&[TokenType::Comma]) {
634	                last_expr = true;
635	            }
636	        }
637	
638	        Expr::Array(exprs)
639	    }
640	
641	    // ---------- PRIMARY ----------
642	    fn primary(&mut self) -> Expr {
643	        if self.match_any(&[TokenType::LeftBrace]) {
644	            return self.statement_block();
645	        }
646	
647	        if self.check(TokenType::Ident) {
648	            let item = self.item();
649	
650	            if self.check(TokenType::LeftParen) {
651	                return self.call_function(item);
652	            }
653	            if self.match_any(&[TokenType::Dot]) {
654	                let member_expr = self.member(item);
655	                // NEW: Check for assignment after member access
656	                if self.match_any(&[TokenType::Equal]) {
657	                    let span = self.get_span();
658	                    return Expr::Assign(Box::new(member_expr), Box::new(self.expression()), span);
659	                }
660	                return member_expr;
661	            }
662	            if self.match_any(&[TokenType::Equal]) {
663	                let span = self.get_span();
664	                return Expr::Assign(
665	                    Box::new(Expr::Variable(item, self.get_span())),
666	                    Box::new(self.expression()),
667	                    span,
668	                );
669	            }
670	            return Expr::Variable(item, self.get_span());
671	        }
672	
673	        if self.match_any(&[TokenType::Float]) {
674	            return Expr::Float(self.previous().literal.parse().unwrap_or(0.0));
675	        }
676	
677	        if self.match_any(&[TokenType::Int]) {
678	            return Expr::Int(self.previous().literal.parse().unwrap_or(0));
679	        }
680	
681	        if self.match_any(&[TokenType::True]) {
682	            return Expr::Bool(true);
683	        }
684	
685	        if self.match_any(&[TokenType::False]) {
686	            return Expr::Bool(false);
687	        }
688	
689	        if self.match_any(&[TokenType::String]) {
690	            return Expr::Str(self.previous().literal.clone());
691	        }
692	
693	        if self.match_any(&[TokenType::Char]) {
694	            return Expr::Char(self.previous().literal.clone());
695	        }
696	
697	        if self.match_any(&[TokenType::LeftParen]) {
698	            let expr = self.expression();
699	            self.consume(TokenType::RightParen, "Expected ')'.");
700	            return expr;
701	        }
702	
703	        if self.match_any(&[TokenType::QuestionMark]) {
704	            return self.if_statement(true);
705	        }
706	
707	        if self.match_any(&[TokenType::This]) {
708	            return Expr::This(self.get_span());
709	        }
710	
711	        if self.match_any(&[TokenType::Lam]) {
712	            return self.define_lambda();
713	        }
714	
715	        if self.match_any(&[TokenType::BackSlash]) {
716	            return self.vector_lit();
717	        }
718	
719	        if self.match_any(&[TokenType::LeftBrack]) {
720	            return self.array_lit();
721	        }
722	
723	        Expr::Nothing()
724	    }
725	
726	    fn get_type(&mut self) -> Type {
727	        if self.match_any(&[TokenType::Ident]) {
728	            let name = self.previous().lexeme.clone();
729	
730	            if self.match_any(&[TokenType::LessLess]) {
731	                let mut gens = vec![];
732	
733	                loop {
734	                    gens.push(self.get_type());
735	                    if !self.match_any(&[TokenType::Comma]) {
736	                        break;
737	                    }
738	                }
739	
740	                self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
741	                return Type::with_generics(&name, gens);
742	            }
743	
744	            return Type::simple(&name);
745	        } else if self.match_any(&[TokenType::LeftBrack]) {
746	            let mut gens = vec![];
747	
748	            loop {
749	                gens.push(self.get_type());
750	                if !self.match_any(&[TokenType::Comma]) {
751	                    break;
752	                }
753	            }
754	
755	            self.consume(TokenType::RightBrack, "Expected '>' after generics");
756	            return Type::with_generics("arr", gens);
757	        }
758	
759	        nil_type()
760	    }
