771	    fn item(&mut self) -> String {
772	        self.consume(TokenType::Ident, "Expected item.");
773	        let item = self.previous().lexeme.clone();
774	        item
775	    }
776	
777	    fn ident(&mut self) -> String {
778	        self.consume(TokenType::Ident, "Expected identifier.");
779	        let ident = self.previous().lexeme.clone();
780	        ident
781	    }
782	
783	    fn match_any(&mut self, types: &[TokenType]) -> bool {
784	        for t in types {
785	            if self.check(*t) {
786	                self.advance();
787	                return true;
788	            }
789	        }
790	        false
791	    }
792	    fn check(&self, token_type: TokenType) -> bool {
793	        !self.is_at_end() && self.peek().token_type == token_type
794	    }
795	
796	    fn peek_next(&self, token_type: TokenType) -> bool {
797	        self.tokens
798	            .get(self.current + 1)
799	            .map(|t| t.token_type == token_type)
800	            .unwrap_or(false)
801	    }
802	
803	    fn peek_next_next(&self, token_type: TokenType) -> bool {
804	        self.tokens
805	            .get(self.current + 2)
806	            .map(|t| t.token_type == token_type)
807	            .unwrap_or(false)
808	    }
809	
810	    fn consume(&mut self, token_type: TokenType, message: &str) -> Token {
811	        if self.check(token_type) {
812	            self.advance()
813	        } else {
814	            let t = self.peek();
815	            error(
816	                self.get_span(),
817	                format!("{} Found: {}", message, t.token_type).as_str(),
818	                "parsing",
819	            );
820	            self.advance();
821	            Token::nil()
822	        }
823	    }
824	
825	    fn advance(&mut self) -> Token {
826	        if !self.is_at_end() {
827	            self.current += 1;
828	        }
829	        self.previous()
830	    }
831	
832	    fn is_at_end(&self) -> bool {
833	        self.peek().token_type == TokenType::EOF
834	    }
835	
836	    fn peek(&self) -> Token {
837	        self.tokens
838	            .get(self.current)
839	            .cloned()
840	            .unwrap_or_else(Token::nil)
841	    }
842	
843	    fn previous(&self) -> Token {
844	        self.tokens
845	            .get(self.current.saturating_sub(1))
846	            .cloned()
847	            .unwrap_or_else(Token::nil)
848	    }
849	}
850	
851	// Grammar:
852	/*
853	statement_block -> "{" ( statement )* "}"
854	statement       -> ( print | declaration | expression | return | function ) ";"
855	
856	print           -> "$" ( "$" )? expression
857	declaration     -> "#" ( "@" )? IDENTIFIER ( ":" type )? ( "=" expression )? // need one or both
858	return          -> "ret" expression
859	while           -> "£" expression statement_block
860	
861	if_statement    -> "?" expression statement_block ( "~?" expression statement_block )* ( "~" statement_block )?
862	function_call   -> IDENTIFIER "(" (expression)* ")"
863	function        -> "fn" ( "<<" IDENTIFIER* ">>" )? IDENTIFIER ( "(" (IDENTIFIER ":" IDENTIFIER)* ")" )? type? statement_block
864	
865	type            -> IDENTIFIER | "[" type* "]" | "<<" type* ">>"
866	
867	expression      -> bool
868	bool            -> compare ( ( "&" | "|" ) compare )*
869	compare         -> term ( ( "==" | ">=" | "<=" | ">" | "<" | "!=" ) term )*
870	term            -> factor ( ( "+" | "-" ) factor )*
871	factor          -> unary ( ( "*" | "/" | "%" ) unary )*
872	unary           -> ( "-" | "+" ) unary | power
873	power           -> nth ( ( "**" ) nth )*
874	nth             -> primary ( "[" expression "]" )?
875	primary         -> NUMBER | STRING | BOOLEAN | IDENTIFIER | "(" expression ")" | statement_block | if_statement | function_call
876	
877	*/
878

1	use crate::error;
2	use crate::span::Span;
3	use crate::token::Token;
4	use crate::token_type::TokenType;
5	use std::collections::HashMap;
6	
7	pub struct Scanner {
8	    source: String,
9	    tokens: Vec<Token>,
10	    start: usize,
11	    current: usize,
12	    line: usize,
13	    column: usize,
14	    keywords: HashMap<String, TokenType>,
15	    prev_c: char,
16	}
17	
18	impl Scanner {
19	    pub fn new(source: String) -> Self {
20	        let mut keywords = HashMap::new();
21	
22	        keywords.insert("cls".into(), TokenType::Cls);
23	        keywords.insert("ret".into(), TokenType::Ret);
24	        keywords.insert("comp".into(), TokenType::Comp);
25	        keywords.insert("stc".into(), TokenType::Stc);
26	        keywords.insert("ovr".into(), TokenType::Ovr);
27	        keywords.insert("err".into(), TokenType::Err);
28	        keywords.insert("del".into(), TokenType::Del);
29	        keywords.insert("use".into(), TokenType::Use);
30	        keywords.insert("for".into(), TokenType::For);
31	        keywords.insert("fn".into(), TokenType::Fn);
32	        keywords.insert("mac".into(), TokenType::Mac);
33	        keywords.insert("lam".into(), TokenType::Lam);
34	        keywords.insert("std".into(), TokenType::Std);
35	
36	        Scanner {
37	            source,
38	            tokens: Vec::new(),
39	            start: 0,
40	            current: 0,
41	            line: 1,
42	            column: 1,
43	            keywords,
44	            prev_c: '\0',
45	        }
46	    }
47	
48	    pub fn scan_tokens(&mut self) -> &Vec<Token> {
49	        while !self.is_at_end() {
50	            self.start = self.current;
51	            self.scan_token();
52	        }
53	
54	        self.tokens.push(Token::new(
55	            TokenType::EOF,
56	            "".into(),
57	            "".into(),
58	            self.line,
59	            self.column,
60	        ));
61	        &self.tokens
62	    }
63	
64	    fn is_at_end(&self) -> bool {
65	        self.current >= self.source.len()
66	    }
67	
68	    fn scan_token(&mut self) {
69	        let c = self.advance();
70	        match c {
71	            '(' => self.add_token(TokenType::LeftParen),
72	            ')' => self.add_token(TokenType::RightParen),
73	            '{' => self.add_token(TokenType::LeftBrace),
74	            '}' => self.add_token(TokenType::RightBrace),
75	            '[' => self.add_token(TokenType::LeftBrack),
76	            ']' => self.add_token(TokenType::RightBrack),
77	            '&' => self.add_token(TokenType::And),
78	            '|' => self.add_token(TokenType::Or),
79	            ',' => self.add_token(TokenType::Comma),
80	            '.' => self.add_token(TokenType::Dot),
81	            '%' => self.add_token(TokenType::Mod),
82	            '-' => {
83	                if self.match_char('>') {
84	                    self.add_token(TokenType::MinusRight);
85	                } else {
86	                    self.add_token(TokenType::Minus);
87	                }
88	            }
89	            '+' => self.add_token(TokenType::Plus),
90	            ';' => self.add_token(TokenType::Semicolon),
91	            ':' => {
92	                if self.match_char(':') {
93	                    self.add_token(TokenType::DoubleColon);
94	                } else {
95	                    self.add_token(TokenType::Colon);
96	                }
97	            }
98	            '*' => {
99	                if self.match_char('*') {
100	                    self.add_token(TokenType::StarStar);
101	                } else {
102	                    self.add_token(TokenType::Star);
103	                }
104	            }
105	            '~' => {
106	                if self.match_char('?') {
107	                    self.add_token(TokenType::TildeQuestionMark);
108	                } else {
109	                    self.add_token(TokenType::Tilde);
110	                }
111	            }
112	            '?' => self.add_token(TokenType::QuestionMark),
113	            '$' => {
114	                if self.match_char('?') {
115	                    self.add_token(TokenType::DollarQuestionMark);
116	                } else {
117	                    self.add_token(TokenType::Dollar);
118	                }
119	            }
120	            '^' => {
121	                if self.match_char('^') {
122	                    self.add_token(TokenType::DoubleUpArrow);
123	                } else {
124	                    self.add_token(TokenType::UpArrow);
125	                }
126	            }
127	            '!' => {
128	                if self.match_char('=') {
129	                    self.add_token(TokenType::BangEqual);
130	                } else {
131	                    self.add_token(TokenType::Bang);
132	                }
133	            }
134	            '=' => {
135	                if self.match_char('=') {
136	                    self.add_token(TokenType::EqualEqual);
137	                } else {
138	                    self.add_token(TokenType::Equal);
139	                }
140	            }
141	            '<' => {
142	                if self.match_char('=') {
143	                    self.add_token(TokenType::LessEqual);
144	                } else if self.match_char('<') {
145	                    self.add_token(TokenType::LessLess);
146	                } else {
147	                    self.add_token(TokenType::Less);
148	                }
149	            }
150	            '>' => {
151	                if self.match_char('=') {
152	                    self.add_token(TokenType::GreaterEqual);
153	                } else if self.match_char('>') {
154	                    self.add_token(TokenType::GreaterGreater);
155	                } else {
156	                    self.add_token(TokenType::Greater);
157	                }
158	            }
159	            '#' => {
160	                self.add_token(TokenType::Hash);
161	            }
162	            '@' => self.add_token(TokenType::At),
163	            '£' => self.add_token(TokenType::Pound),
164	            '¬' => self.add_token(TokenType::NotSign),
165	            '/' => {
166	                if self.match_char('/') {
167	                    // Single-line comment
168	                    while self.peek() != '\n' && !self.is_at_end() {
169	                        self.advance();
170	                    }
171	                } else if self.match_char('*') {
172	                    // Multi-line comment
173	                    self.block_comment();
174	                } else {
175	                    self.add_token(TokenType::Slash);
176	                }
177	            }
178	            '\\' => self.add_token(TokenType::BackSlash),
179	            ' ' | '\r' | '\t' | '\n' => {}
180	            '`' => self.backtick(),
181	            '"' => self.string(),
182	            '\'' => self.character(),
183	            _ => {
184	                if c.is_ascii_digit() {
185	                    self.number();
186	                } else if self.alpha(c) {
187	                    self.identifier();
188	                } else {
189	                    error(
190	                        Span {
191	                            line: self.line,
192	                            column: self.column,
193	                        },
194	                        "Unexpected character.",
195	                        "scanning",
196	                    );
197	                }
198	            }
199	        }
200	    }
201	
202	    fn advance(&mut self) -> char {
203	        let c = self.source[self.current..].chars().next().unwrap();
204	        self.current += c.len_utf8();
205	
206	        if c == '\n' {
207	            self.line += 1;
208	            self.column = 1;
209	        } else {
210	            self.column += 1;
211	        }
212	
213	        c
214	    }
215	
216	    fn add_token(&mut self, token_type: TokenType) {
217	        self.add_token_literal(token_type, "".into());
218	    }
219	
220	    fn add_token_literal(&mut self, token_type: TokenType, literal: String) {
221	        let text = self.source[self.start..self.current].to_string();
222	
223	        let token_column = self.column - text.chars().count();
224	
225	        self.tokens.push(Token::new(
226	            token_type,
227	            text,
228	            literal,
229	            self.line,
230	            token_column.max(1),
231	        ));
232	    }
233	
234	    fn match_char(&mut self, expected: char) -> bool {
235	        if self.is_at_end() {
236	            return false;
237	        }
238	
239	        if self.peek() != expected {
240	            return false;
241	        }
242	
243	        self.advance();
244	        true
245	    }
246	
247	    fn peek(&self) -> char {
248	        if self.is_at_end() {
249	            '\0'
250	        } else {
251	            self.source[self.current..].chars().next().unwrap()
252	        }
253	    }
254	
255	    fn peek_next(&self) -> char {
256	        let mut chars = self.source[self.current..].chars();
257	        chars.next();
258	        chars.next().unwrap_or('\0')
259	    }
260	
261	    fn alpha(&mut self, c: char) -> bool {
262	        let output =
263	            (c.is_ascii_alphabetic() || c == '_' || c == '¬') && !(c == '_' && self.prev_c == '_');
264	        self.prev_c = c;
265	        output
266	    }
267	
268	    fn alpha_numeric(&mut self, c: char) -> bool {
269	        self.alpha(c) || c.is_ascii_digit()
270	    }
271	
272	    fn string(&mut self) {
273	        let mut value = String::new();
274	
275	        while !self.is_at_end() {
276	            let c = self.advance();
277	
278	            match c {
279	                '"' => {
280	                    // End of string
281	                    self.add_token_literal(TokenType::String, value);
282	                    return;
283	                }
284	                '\\' => {
285	                    if self.is_at_end() {
286	                        error(
287	                            Span {
288	                                line: self.line,
289	                                column: self.column,
290	                            },
291	                            "Unterminated escape sequence in string.",
292	                            "lexing",
293	                        );
294	                        return;
295	                    }
296	
297	                    let esc = self.advance();
298	                    match esc {
299	                        'n' => value.push('\n'),
300	                        't' => value.push('\t'),
301	                        'r' => value.push('\r'),
302	                        '\\' => value.push('\\'),
303	                        'x' => value.push_str("\\x"),
304	                        '"' => value.push('"'),
305	                        _ => {
306	                            error(
307	                                Span {
308	                                    line: self.line,
309	                                    column: self.column,
310	                                },
311	                                &format!("Invalid escape sequence: \\{}", esc),
312	                                "lexing",
313	                            );
314	                            return;
315	                        }
316	                    }
317	                }
318	                _ => value.push(c),
319	            }
320	        }
321	
322	        error(
323	            Span {
324	                line: self.line,
325	                column: self.column,
326	            },
327	            "Unterminated string literal.",
328	            "lexing",
329	        );
330	    }
331	
332	    fn number(&mut self) {
333	        while self.peek().is_ascii_digit() {
334	            self.advance();
335	        }
336	
337	        // Look for fractional part
338	        if self.peek() == '.' && self.peek_next().is_ascii_digit() {
339	            self.advance(); // consume '.'
340	            while self.peek().is_ascii_digit() {
341	                self.advance();
342	            }
343	            let value = self.source[self.start..self.current].to_string();
344	            self.add_token_literal(TokenType::Float, value);
345	        } else {
346	            let value = self.source[self.start..self.current].to_string();
347	            self.add_token_literal(TokenType::Int, value);
348	        }
349	    }
350	
351	    fn identifier(&mut self) {
352	        while self.alpha_numeric(self.peek()) {
353	            self.advance();
354	        }
355	
356	        // Handle '::' type sequences like 'str::i32'
357	        while self.peek() == ':' && self.peek_next() == ':' {
358	            self.advance(); // consume first ':'
359	            self.advance(); // consume second ':'
360	
361	            // continue scanning the next identifier part
362	            while self.alpha_numeric(self.peek()) {
363	                self.advance();
364	            }
365	        }
366	
367	        let text = self.source[self.start..self.current].to_string();
368	        if let Some(token_type) = self.keywords.get(&text) {
369	            self.add_token(*token_type);
370	        } else {
371	            self.add_token(TokenType::Ident);
372	        }
373	    }
374	
375	    fn character(&mut self) {
376	        if self.is_at_end() {
377	            error(
378	                Span {
379	                    line: self.line,
380	                    column: self.column,
381	                },
382	                "Unterminated character literal.",
383	                "lexing",
384	            );
385	            return;
386	        }
387	
388	        let c = self.advance();
389	        let value = if c == '\\' {
390	            if self.is_at_end() {
391	                error(
392	                    Span {
393	                        line: self.line,
394	                        column: self.column,
395	                    },
396	                    "Unterminated escape sequence.",
397	                    "lexing",
398	                );
399	                return;
400	            }
401	            let esc = self.advance();
402	            match esc {
403	                'n' => "\n".to_string(),
404	                't' => "\t".to_string(),
405	                '\\' => "\\".to_string(),
406	                '\'' => "'".to_string(),
407	                'r' => "\r".to_string(),
408	                _ => {
409	                    error(
410	                        Span {
411	                            line: self.line,
412	                            column: self.column,
413	                        },
414	                        &format!("Invalid escape sequence: \\{}", esc),
415	                        "lexing",
416	                    );
417	                    return;
418	                }
419	            }
420	        } else {
421	            c.to_string()
422	        };
423	
424	        if self.peek() != '\'' {
425	            error(
426	                Span {
427	                    line: self.line,
428	                    column: self.column,
429	                },
430	                "Character literal too long or missing closing quote.",
431	                "lexing",
432	            );
433	            return;
434	        }
435	
436	        self.advance(); // Consume closing quote
437	        self.add_token_literal(TokenType::Char, value);
438	    }
439	
440	    fn backtick(&mut self) {
441	        if self.is_at_end() {
442	            error(
443	                Span {
444	                    line: self.line,
445	                    column: self.column,
446	                },
447	                "Expected character after backtick (`)",
448	                "lexing",
449	            );
450	            return;
451	        }
452	
453	        let c = self.advance();
454	        match c {
455	            'f' => self.add_token(TokenType::False),
456	            't' => self.add_token(TokenType::True),
457	            's' => self.tokens.push(Token::new(
458	                TokenType::String,
459	                String::new(),
460	                String::new(),
461	                self.line,
462	                self.column,
463	            )),
464	            'v' => self.add_token(TokenType::This),
465	            _ => {
466	                error(
467	                    Span {
468	                        line: self.line,
469	                        column: self.column,
470	                    },
471	                    "Invalid character after backtick (`)",
472	                    "lexing",
473	                );
474	                return;
475	            }
476	        }
477	
478	        if self.alpha(self.peek()) {
479	            error(
480	                Span {
481	                    line: self.line,
482	                    column: self.column,
483	                },
484	                "Only a single character should be after a backtick (`)",
485	                "lexing",
486	            );
487	        }
488	    }
489	
490	    fn block_comment(&mut self) {
491	        while !self.is_at_end() {
492	            if self.peek() == '*' {
493	                self.advance();
494	                if self.peek() == '/' {
495	                    self.advance();
496	                    return;
497	                }
498	            } else {
499	                self.advance();
500	            }
501	        }
502	
503	        error(
504	            Span {
505	                line: self.line,
506	                column: self.column,
507	            },
508	            "Unterminated block comment.",
509	            "lexing",
510	        );
511	    }
512	}
