3	use std::collections::HashMap;
4	
5	#[derive(Clone)]
6	pub struct TypeEnvironment {
7	    scopes: Vec<HashMap<String, Type>>,
8	    gens: Vec<HashMap<String, Type>>,
9	}
10	
11	impl TypeEnvironment {
12	    pub fn new() -> Self {
13	        Self {
14	            scopes: vec![HashMap::new()],
15	            gens: vec![HashMap::new()],
16	        }
17	    }
18	
19	    pub fn push(&mut self) {
20	        self.scopes.push(HashMap::new());
21	    }
22	
23	    pub fn pop(&mut self) {
24	        self.scopes.pop();
25	    }
26	
27	    pub fn push_func(&mut self) {
28	        self.gens.push(HashMap::new());
29	    }
30	
31	    pub fn pop_func(&mut self) {
32	        self.gens.pop();
33	    }
34	
35	    pub fn get_gen(&mut self, name: String) -> Type {
36	        self.gens.last().unwrap().get(&name).unwrap().clone()
37	    }
38	
39	    pub fn add_gen(&mut self, name: String, ty: Type) {
40	        self.gens.last_mut().unwrap().insert(name, ty);
41	    }
42	
43	    pub fn declare(&mut self, name: String, ty: Type) {
44	        self.scopes.last_mut().unwrap().insert(name, ty);
45	    }
46	
47	    pub fn get(&self, name: &str) -> Type {
48	        for scope in self.scopes.iter().rev() {
49	            if let Some(t) = scope.get(name) {
50	                return t.clone();
51	            }
52	        }
53	
54	        panic!("Type error: unknown variable {}", name);
55	    }
56	}
57	
58	#[derive(Debug, Clone, PartialEq, Eq, Hash)]
59	pub enum Type {
60	    Concrete { name: String, generics: Vec<Type> }, // vec<<i32>>
61	    Conceptual(String),                             // T, U, etc
62	}
63	
64	impl Type {
65	    pub fn simple(name: &str) -> Self {
66	        Type::Concrete {
67	            name: name.into(),
68	            generics: vec![],
69	        }
70	    }
71	
72	    pub fn is_generic(&self) -> bool {
73	        matches!(self, Type::Conceptual(_))
74	    }
75	
76	    pub fn conceptual(name: &str) -> Self {
77	        Type::Conceptual(name.into())
78	    }
79	
80	    pub fn generics(&self) -> &[Type] {
81	        match self {
82	            Type::Concrete { generics, .. } => generics,
83	            _ => &[],
84	        }
85	    }
86	
87	    pub fn with_generics(name: &str, gens: Vec<Type>) -> Self {
88	        Type::Concrete {
89	            name: name.into(),
90	            generics: gens,
91	        }
92	    }
93	
94	    pub fn name(&self) -> &str {
95	        match self {
96	            Type::Concrete { name, .. } => name,
97	            Type::Conceptual(n) => n,
98	        }
99	    }
100	
101	    pub fn has_tag(&self, tag: &str) -> bool {
102	        self.name() == tag
103	    }
104	}
105	
106	impl From<&str> for Type {
107	    fn from(name: &str) -> Self {
108	        Type::simple(name)
109	    }
110	}
111	
112	impl From<String> for Type {
113	    fn from(name: String) -> Self {
114	        Type::simple(&name)
115	    }
116	}
117	
118	impl fmt::Display for Type {
119	    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
120	        match self {
121	            Type::Conceptual(n) => write!(f, "{}", n),
122	            Type::Concrete { name, generics } => {
123	                if generics.is_empty() {
124	                    write!(f, "{}", name)
125	                } else {
126	                    let g = generics
127	                        .iter()
128	                        .map(|x| x.to_string())
129	                        .collect::<Vec<_>>()
130	                        .join(", ");
131	                    write!(f, "{}<<{}>>", name, g)
132	                }
133	            }
134	        }
135	    }
136	}
137	
138	pub fn nil_type() -> Type {
139	    Type::simple("arr")
140	}
141	
142	pub fn unify(pattern: &Type, actual: &Type, bindings: &mut HashMap<String, Type>) -> bool {
143	    match (pattern, actual) {
144	        (Type::Conceptual(name), t) => {
145	            if let Some(bound) = bindings.get(name) {
146	                bound == t
147	            } else {
148	                bindings.insert(name.clone(), t.clone());
149	                true
150	            }
151	        }
152	
153	        (
154	            Type::Concrete {
155	                name: a,
156	                generics: ag,
157	            },
158	            Type::Concrete {
159	                name: b,
160	                generics: bg,
161	            },
162	        ) => {
163	            if a != b || ag.len() != bg.len() {
164	                return false;
165	            }
166	
167	            for (x, y) in ag.iter().zip(bg.iter()) {
168	                if !unify(x, y, bindings) {
169	                    return false;
170	                }
171	            }
172	            true
173	        }
174	
175	        _ => false,
176	    }
177	}
178	
179	pub fn substitute(t: &Type, map: &HashMap<String, Type>, span: Span) -> Type {
180	    match t {
181	        Type::Conceptual(n) => map.get(n).cloned().unwrap_or(t.clone()),
182	
183	        Type::Concrete { name, generics } => Type::Concrete {
184	            name: name.clone(),
185	            generics: generics.iter().map(|g| substitute(g, map, span)).collect(),
186	        },
187	    }
188	}
