1	use crate::error;
2	use crate::expr::Expr;
3	use crate::span::Span;
4	use crate::type_env::{nil_type, Type, TypeEnvironment};
5	use crate::value::{func_val, native_func, nil, Func, Value};
6	use crate::variable::Variable;
7	use cobject::CWindow;
8	use std::collections::HashMap;
9	
10	pub struct RuntimeEnvironment {
11	    pub(crate) scopes: Vec<HashMap<String, usize>>,
12	    this: Vec<String>,
13	    window: Option<CWindow>,
14	    storage: Vec<Option<Variable>>,
15	}
16	
17	impl RuntimeEnvironment {
18	    pub fn new() -> Self {
19	        Self {
20	            scopes: vec![HashMap::new()],
21	            this: vec![],
22	            window: None,
23	            storage: vec![],
24	        }
25	    }
26	
27	    // ------------ THIS -----------
28	
29	    pub fn end_this(&mut self) {
30	        self.this.pop();
31	    }
32	
33	    pub fn this(&self) -> String {
34	        self.this.last().unwrap().clone()
35	    }
36	
37	    pub fn new_this(&mut self, this: &str) {
38	        self.this.push(this.to_string());
39	    }
40	
41	    // ---------- SCOPES ----------
42	
43	    pub fn push_scope(&mut self) {
44	        self.scopes.push(HashMap::new());
45	    }
46	
47	    pub fn pop_scope(&mut self) {
48	        for pointer in self.scopes.last().unwrap().values() {
49	            self.storage[*pointer] = None;
50	        }
51	
52	        self.scopes.pop();
53	    }
54	
55	    // ----------- POINTERS ------------
56	
57	    pub fn new_ptr(&mut self, item: Variable) -> usize {
58	        let id = self.storage.len();
59	        self.storage.push(Some(item));
60	        id
61	    }
62	
63	    pub fn del_ptr(&mut self, id: usize) {
64	        if let Some(slot) = self.storage.get_mut(id) {
65	            *slot = None;
66	        } else {
67	            error(
68	                Span::empty(),
69	                "Invalid pointer ID, could not delete.",
70	                "interpreting",
71	            );
72	        }
73	    }
74	
75	    pub fn set_ptr(&mut self, id: usize, val: Value) {
76	        if let Some(slot) = self.storage.get_mut(id) {
77	            let variable = slot.as_mut().unwrap();
78	            if !variable.is_mutable {
79	                error(
80	                    Span::empty(),
81	                    "Variable not mutable, could not set pointee value",
82	                    "interpreting",
83	                );
84	            }
85	            variable.value = val;
86	        } else {
87	            error(
88	                Span::empty(),
89	                "Invalid pointer ID, could not set value.",
90	                "interpreting",
91	            );
92	        }
93	    }
94	
95	    pub fn get_ptr(&mut self, id: usize) -> &mut Variable {
96	        match self.storage.get_mut(id) {
97	            Some(Some(var)) => var,
98	            _ => {
99	                error(
100	                    Span::empty(),
101	                    "Invalid or freed pointer dereference.",
102	                    "interpreting",
103	                );
104	                panic!("Invalid pointer dereference");
105	            }
106	        }
107	    }
108	
109	    // ---------- VARIABLES ----------
110	
111	    pub fn declare(&mut self, name: String, value: Value, is_mutable: bool) {
112	        let id = self.alloc_var(Variable::new(value, is_mutable));
113	
114	        let scope = self.scopes.last_mut().unwrap();
115	
116	        if scope.contains_key(&name) {
117	            error(
118	                Span::empty(),
119	                format!("Variable '{}' already defined", name).as_str(),
120	                "interpreting",
121	            );
122	            return;
123	        }
124	
125	        scope.insert(name, id);
126	    }
127	
128	    pub fn assign(&mut self, name: &str, value: Value, span: Span) {
129	        for scope in self.scopes.iter().rev() {
130	            if let Some(&id) = scope.get(name) {
131	                if let Some(Some(var)) = self.storage.get_mut(id) {
132	                    if !var.is_mutable {
133	                        error(
134	                            span,
135	                            format!("Variable '{}' not mutable", name).as_str(),
136	                            "interpreting",
137	                        );
138	                        return;
139	                    }
140	
141	                    var.value = value;
142	                    return;
143	                }
144	            }
145	        }
146	
147	        error(
148	            span,
149	            format!("Undefined variable '{}'.", name).as_str(),
150	            "interpreting",
151	        );
152	    }
153	
154	    pub fn get(&self, name: &str, span: Span) -> Variable {
155	        for scope in self.scopes.iter().rev() {
156	            if let Some(&id) = scope.get(name) {
157	                if let Some(Some(var)) = self.storage.get(id) {
158	                    return var.clone();
159	                }
160	            }
161	        }
162	
163	        error(
164	            span,
165	            format!("Undefined variable '{}'.", name).as_str(),
166	            "interpreting",
167	        );
168	        Variable::new(nil(), false)
169	    }
170	
171	    pub fn delete(&mut self, name: &str) {
172	        for scope in self.scopes.iter_mut().rev() {
173	            if let Some(id) = scope.remove(name) {
174	                if let Some(slot) = self.storage.get_mut(id) {
175	                    *slot = None;
176	                }
177	                return;
178	            }
179	        }
180	
181	        error(
182	            Span::empty(),
183	            format!("Undefined variable '{}'.", name).as_str(),
184	            "interpreting",
185	        );
186	    }
187	
188	    // ---------- FUNCTIONS ----------
189	
190	    pub fn make_func(
191	        &mut self,
192	        name: &str,
193	        block: Box<Expr>,
194	        return_type: Type,
195	        parameters: Vec<(String, Type)>,
196	        gens: Vec<String>,
197	        is_mutable: bool,
198	        span: Span,
199	    ) {
200	        let scope = self.scopes.last_mut().unwrap();
201	
202	        if scope.contains_key(name) {
203	            error(
204	                span,
205	                format!("'{}' already defined", name).as_str(),
206	                "interpreting",
207	            );
208	            return;
209	        }
210	
211	        let func_var = Variable::new_func(block, parameters, return_type, gens, is_mutable);
212	
213	        let id = self.storage.len();
214	        self.storage.push(Some(func_var));
215	        scope.insert(name.to_string(), id);
216	    }
217	
218	    pub fn declare_native(
219	        &mut self,
220	        name: &str,
221	        func: fn(&mut RuntimeEnvironment, &mut TypeEnvironment, Vec<Value>, Span) -> Value,
222	    ) {
223	        let scope = self.scopes.last_mut().unwrap();
224	
225	        let id = self.storage.len();
226	        self.storage
227	            .push(Some(Variable::new(native_func(func), false)));
228	
229	        scope.insert(name.to_string(), id);
230	    }
231	
232	    pub fn get_func(&self, name: &str, span: Span) -> Func {
233	        let var = self.get(name, span);
234	
235	        var.value.body.unwrap_or_else(|| {
236	            error(
237	                Span::empty(),
238	                format!("Variable '{}' is not a function", name).as_str(),
239	                "interpreting",
240	            );
241	            nil_func().value.body.unwrap()
242	        })
243	    }
244	
245	    pub fn make_window(&mut self, name: String) {
246	        self.window = Some(CWindow::new(800, 800, name));
247	    }
248	
249	    pub fn get_window(&mut self) -> &mut CWindow {
250	        self.window
251	            .as_mut()
252	            .expect("Window doesn't exist, could not fetch window")
253	    }
254	
255	    fn alloc_var(&mut self, var: Variable) -> usize {
256	        for (i, slot) in self.storage.iter_mut().enumerate() {
257	            if slot.is_none() {
258	                *slot = Some(var);
259	                return i;
260	            }
261	        }
262	
263	        let id = self.storage.len();
264	        self.storage.push(Some(var));
265	        id
266	    }
267	}
268	
269	// ---------- INTERNAL ----------
270	
271	fn nil_func() -> Variable {
272	    Variable {
273	        value: func_val(Func::new(
274	            Box::new(Expr::StmtBlockWithScope(vec![], Span::empty())),
275	            vec![],
276	            nil_type(),
277	            vec![],
278	        )),
279	        is_mutable: false,
280	    }
281	}
